            string name,
            InputType type,
            bool isRequired = false,
            bool isReadOnly = false,
            bool isDiscriminator = false,
            bool isHttpMetadata = false,
            bool isApiVersion = false,
            InputConstant? defaultValue = null,
            string? wireName = null,
            string? summary = null,
            string? serializedName = null,
            string? doc = null)
