            var discriminatorProperty = InputFactory.Property(
                "kind", InputPrimitiveType.String, isRequired: true, isDiscriminator: true, serializedName: "kind");

            var derivedModel = InputFactory.Model(
                "TypeAPolyDevice",
                usage: InputModelTypeUsage.Output | InputModelTypeUsage.Input | InputModelTypeUsage.Json,
                properties: [
                    InputFactory.Property("description", InputPrimitiveType.String, isRequired: false, serializedName: "description"),
                    InputFactory.Property("id", InputPrimitiveType.String, isReadOnly: true, serializedName: "id"),
                    InputFactory.Property("type", InputPrimitiveType.String, isReadOnly: true, serializedName: "type"),
                    InputFactory.Property("name", InputPrimitiveType.String, isReadOnly: true, serializedName: "name"),
                ],
                discriminatedKind: "TypeA");

            var baseModel = InputFactory.Model(
                "PolyDeviceData",
                properties: [
                    discriminatorProperty,
                    InputFactory.Property("id", InputPrimitiveType.String, isReadOnly: true, serializedName: "id"),
                    InputFactory.Property("type", InputPrimitiveType.String, isReadOnly: true, serializedName: "type"),
                    InputFactory.Property("name", InputPrimitiveType.String, isReadOnly: true, serializedName: "name"),
                ],
                derivedModels: [derivedModel],
                discriminatedModels: new Dictionary<string, InputModelType> { { "TypeA", derivedModel } });

