            var uuidType = new InputPrimitiveType(InputPrimitiveTypeKind.String, "uuid", "Azure.Core.uuid");
            var subsIdOpParam = InputFactory.PathParameter("subscriptionId", uuidType, isRequired: true);
            var rgOpParam = InputFactory.PathParameter("resourceGroupName", InputPrimitiveType.String, isRequired: true);
            var deviceNameOpParam = InputFactory.PathParameter("deviceName", InputPrimitiveType.String, isRequired: true);

            var getOperation = InputFactory.Operation(
                name: "get",
                responses: [responseType],
                parameters: [subsIdOpParam, rgOpParam, deviceNameOpParam],
                path: "/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Microsoft.Poly/polyDevices/{deviceName}");

            var subscriptionIdParam = InputFactory.MethodParameter("subscriptionId", uuidType, location: InputRequestLocation.Path);
            var resourceGroupParam = InputFactory.MethodParameter("resourceGroupName", InputPrimitiveType.String, location: InputRequestLocation.Path);
            var deviceNameParam = InputFactory.MethodParameter("deviceName", InputPrimitiveType.String, location: InputRequestLocation.Path, isRequired: true);

            var getMethod = InputFactory.BasicServiceMethod("get", getOperation, parameters: [deviceNameParam, subscriptionIdParam, resourceGroupParam], crossLanguageDefinitionId: Guid.NewGuid().ToString());

            var resourceIdPattern = "/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Microsoft.Poly/polyDevices/{deviceName}";
            var armProviderDecorator = BuildArmProviderSchema(baseModel, [
                new ResourceMethod(ResourceOperationKind.Read, getMethod, getMethod.Operation.Path, ResourceScope.ResourceGroup, resourceIdPattern, null!)
            ], resourceIdPattern, "Microsoft.Poly/polyDevices", null, ResourceScope.ResourceGroup, "PolyDeviceData");

            var client = InputFactory.Client(
                "PolyClient",
                methods: [getMethod],
                decorators: [armProviderDecorator],
                crossLanguageDefinitionId: "Test.PolyClient");

