                .FirstOrDefault(p => p is ResourceSerializationProvider) as ResourceSerializationProvider;
            Assert.IsNotNull(serializationProvider);

            // Verify DataDeserializationInstance property does NOT exist (abstract data type)
            var dataDeserializationInstanceProp = serializationProvider!.Properties
                .FirstOrDefault(p => p.Name == "DataDeserializationInstance");
            Assert.IsNull(dataDeserializationInstanceProp, "DataDeserializationInstance should NOT exist for abstract/discriminated data types");

            // Verify the field s_dataDeserializationInstance does NOT exist
            var dataField = serializationProvider.Fields
                .FirstOrDefault(f => f.Name == "s_dataDeserializationInstance");
            Assert.IsNull(dataField, "s_dataDeserializationInstance field should NOT exist for abstract/discriminated data types");

            // Verify the IJsonModel<T>.Create method body does NOT reference DataDeserializationInstance
            var createMethod = serializationProvider.Methods
                .FirstOrDefault(m => m.Signature.Name == "Create");
            Assert.IsNotNull(createMethod, "IJsonModel<T>.Create method should exist");
            var createBody = createMethod!.BodyStatements?.ToDisplayString();
            Assert.IsNotNull(createBody);
            Assert.That(createBody, Does.Not.Contain("DataDeserializationInstance"),
                "IJsonModel<T>.Create should not reference DataDeserializationInstance for abstract data types");

            // Verify the GetFormatFromOptions method body does NOT reference DataDeserializationInstance
            var getFormatMethod = serializationProvider.Methods
                .FirstOrDefault(m => m.Signature.Name == "GetFormatFromOptions");
            Assert.IsNotNull(getFormatMethod, "IPersistableModel<T>.GetFormatFromOptions method should exist");
            var getFormatBody = getFormatMethod!.BodyStatements?.ToDisplayString();
            Assert.IsNotNull(getFormatBody);
            Assert.That(getFormatBody, Does.Not.Contain("DataDeserializationInstance"),
                "GetFormatFromOptions should not reference DataDeserializationInstance for abstract data types");
            Assert.That(getFormatBody, Does.Contain("\"J\""),
                "GetFormatFromOptions should return \"J\" directly for abstract data types");
        }

        private static InputDecoratorInfo BuildArmProviderSchema(
            InputModelType resourceModel,
            IReadOnlyList<ResourceMethod> methods,
            string resourceIdPattern,
            string resourceType,
            string? singletonResourceName,
            ResourceScope resourceScope,
            string? resourceName)
        {
            var options = new System.Text.Json.JsonSerializerOptions
            {
                PropertyNamingPolicy = System.Text.Json.JsonNamingPolicy.CamelCase,
            };

            var resourceSchema = new Dictionary<string, object?>
            {
                ["resourceModelId"] = resourceModel.CrossLanguageDefinitionId,
                ["resourceIdPattern"] = resourceIdPattern,
                ["resourceType"] = resourceType,
                ["resourceScope"] = resourceScope.ToString(),
                ["methods"] = methods.Select(m => new Dictionary<string, string>
                {
                    ["methodId"] = m.InputMethod.CrossLanguageDefinitionId,
                    ["kind"] = m.Kind.ToString(),
                    ["operationPath"] = m.OperationPath,
                    ["operationScope"] = m.OperationScope.ToString()
                }).ToArray<object>(),
                ["singletonResourceName"] = singletonResourceName,
                ["resourceName"] = resourceName,
            };

            var arguments = new Dictionary<string, BinaryData>
            {
                ["resources"] = BinaryData.FromObjectAsJson(new[] { resourceSchema }, options),
                ["nonResourceMethods"] = BinaryData.FromObjectAsJson(Array.Empty<object>(), options)
            };

            return new InputDecoratorInfo("Azure.ClientGenerator.Core.@armProviderSchema", arguments);
        }
    }
