using Microsoft.TypeSpec.Generator.Input;
using Microsoft.TypeSpec.Generator.Primitives;
using Microsoft.TypeSpec.Generator.Providers;
using NUnit.Framework;

namespace Azure.Generator.Management.Tests.Providers
{
    internal class ResourceSerializationProviderTests
    {
        /// <summary>
        /// Verifies that for a resource with non-abstract data type, the serialization provider
        /// generates the DataDeserializationInstance property and uses it for Create and GetFormatFromOptions.
        /// </summary>
        [Test]
        public void NonAbstractDataType_HasDataDeserializationInstance()
        {
            var (client, models) = InputResourceData.ClientWithResource();
            var plugin = ManagementMockHelpers.LoadMockPlugin(inputModels: () => models, clients: () => [client]);

            var resourceProvider = plugin.Object.OutputLibrary.TypeProviders
                .FirstOrDefault(p => p is ResourceClientProvider) as ResourceClientProvider;
            Assert.IsNotNull(resourceProvider);

            // The serialization provider should have the DataDeserializationInstance property
            var serializationProvider = resourceProvider!.SerializationProviders
                .FirstOrDefault(p => p is ResourceSerializationProvider) as ResourceSerializationProvider;
            Assert.IsNotNull(serializationProvider);

            // Verify DataDeserializationInstance property exists (non-abstract data type)
            var dataDeserializationInstanceProp = serializationProvider!.Properties
                .FirstOrDefault(p => p.Name == "DataDeserializationInstance");
            Assert.IsNotNull(dataDeserializationInstanceProp, "DataDeserializationInstance should exist for non-abstract data types");

            // Verify the field s_dataDeserializationInstance exists
            var dataField = serializationProvider.Fields
                .FirstOrDefault(f => f.Name == "s_dataDeserializationInstance");
            Assert.IsNotNull(dataField, "s_dataDeserializationInstance field should exist for non-abstract data types");
        }

        /// <summary>
        /// Verifies that for a resource with an abstract (discriminated) data type, the serialization provider
        /// does NOT generate the DataDeserializationInstance property to avoid CS0144 (cannot instantiate abstract type).
        /// </summary>
        [Test]
        public void AbstractDiscriminatedDataType_NoDataDeserializationInstance()
        {
            // Create a discriminated base model (abstract resource data type)
            var discriminatorProperty = InputFactory.Property(
                "kind", InputPrimitiveType.String, isRequired: true, isDiscriminator: true, serializedName: "kind");

            var derivedModel = InputFactory.Model(
                "TypeAPolyDevice",
                usage: InputModelTypeUsage.Output | InputModelTypeUsage.Input | InputModelTypeUsage.Json,
                properties: [
                    InputFactory.Property("description", InputPrimitiveType.String, isRequired: false, serializedName: "description"),
                    InputFactory.Property("id", InputPrimitiveType.String, isReadOnly: true, serializedName: "id"),
                    InputFactory.Property("type", InputPrimitiveType.String, isReadOnly: true, serializedName: "type"),
                    InputFactory.Property("name", InputPrimitiveType.String, isReadOnly: true, serializedName: "name"),
                ],
                discriminatedKind: "TypeA");

            var baseModel = InputFactory.Model(
                "PolyDeviceData",
                properties: [
                    discriminatorProperty,
                    InputFactory.Property("id", InputPrimitiveType.String, isReadOnly: true, serializedName: "id"),
                    InputFactory.Property("type", InputPrimitiveType.String, isReadOnly: true, serializedName: "type"),
                    InputFactory.Property("name", InputPrimitiveType.String, isReadOnly: true, serializedName: "name"),
                ],
                derivedModels: [derivedModel],
                discriminatedModels: new Dictionary<string, InputModelType> { { "TypeA", derivedModel } });

            // Debug: check the model
            TestContext.WriteLine($"BaseModel discriminatedKind: {baseModel.DiscriminatedKind}");
            TestContext.WriteLine($"BaseModel discriminatorProperty: {baseModel.DiscriminatorProperty?.Name}");
            TestContext.WriteLine($"BaseModel CLDID: {baseModel.CrossLanguageDefinitionId}");
            TestContext.WriteLine($"DerivedModel discriminatedKind: {derivedModel.DiscriminatedKind}");

            // Create resource operations
            var responseType = InputFactory.OperationResponse(statusCodes: [200], bodytype: baseModel);
            var uuidType = new InputPrimitiveType(InputPrimitiveTypeKind.String, "uuid", "Azure.Core.uuid");
            var subsIdOpParam = InputFactory.PathParameter("subscriptionId", uuidType, isRequired: true);
            var rgOpParam = InputFactory.PathParameter("resourceGroupName", InputPrimitiveType.String, isRequired: true);
            var deviceNameOpParam = InputFactory.PathParameter("deviceName", InputPrimitiveType.String, isRequired: true);

            var getOperation = InputFactory.Operation(
                name: "get",
                responses: [responseType],
                parameters: [subsIdOpParam, rgOpParam, deviceNameOpParam],
                path: "/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Microsoft.Poly/polyDevices/{deviceName}");

            var subscriptionIdParam = InputFactory.MethodParameter("subscriptionId", uuidType, location: InputRequestLocation.Path);
            var resourceGroupParam = InputFactory.MethodParameter("resourceGroupName", InputPrimitiveType.String, location: InputRequestLocation.Path);
            var deviceNameParam = InputFactory.MethodParameter("deviceName", InputPrimitiveType.String, location: InputRequestLocation.Path, isRequired: true);

            var getMethod = InputFactory.BasicServiceMethod("get", getOperation, parameters: [deviceNameParam, subscriptionIdParam, resourceGroupParam], crossLanguageDefinitionId: Guid.NewGuid().ToString());

            var resourceIdPattern = "/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Microsoft.Poly/polyDevices/{deviceName}";
            var armProviderDecorator = BuildArmProviderSchema(baseModel, [
                new ResourceMethod(ResourceOperationKind.Read, getMethod, getMethod.Operation.Path, ResourceScope.ResourceGroup, resourceIdPattern, null!)
            ], resourceIdPattern, "Microsoft.Poly/polyDevices", null, ResourceScope.ResourceGroup, "PolyDeviceData");

            var client = InputFactory.Client(
                "PolyClient",
                methods: [getMethod],
                decorators: [armProviderDecorator],
                crossLanguageDefinitionId: "Test.PolyClient");

            var plugin = ManagementMockHelpers.LoadMockPlugin(inputModels: () => [baseModel, derivedModel], clients: () => [client]);

            // Debug: list all type providers
            var allProviders = plugin.Object.OutputLibrary.TypeProviders.ToList();
            TestContext.WriteLine($"Total type providers: {allProviders.Count}");
            foreach (var provider in allProviders)
            {
                TestContext.WriteLine($"  Provider: {provider.Name} (Type: {provider.GetType().Name})");
            }

            var resourceProviders = allProviders.OfType<ResourceClientProvider>().ToList();
            TestContext.WriteLine($"ResourceClientProvider count: {resourceProviders.Count}");
            foreach (var rp in resourceProviders)
            {
                TestContext.WriteLine($"  Resource: {rp.Name}, Abstract: {rp.ResourceData.DeclarationModifiers.HasFlag(TypeSignatureModifiers.Abstract)}");
                var serializationProviders = rp.SerializationProviders.ToList();
                TestContext.WriteLine($"    SerializationProviders count: {serializationProviders.Count}");
            }

            if (resourceProviders.Count == 0)
            {
                Assert.Fail("No ResourceClientProvider found in output library.");
            }

            var resourceProvider = resourceProviders[0];
            var serializationProvider = resourceProvider!.SerializationProviders
                .FirstOrDefault(p => p is ResourceSerializationProvider) as ResourceSerializationProvider;
            Assert.IsNotNull(serializationProvider);

            // Verify DataDeserializationInstance property does NOT exist (abstract data type)
            var dataDeserializationInstanceProp = serializationProvider!.Properties
                .FirstOrDefault(p => p.Name == "DataDeserializationInstance");
            Assert.IsNull(dataDeserializationInstanceProp, "DataDeserializationInstance should NOT exist for abstract/discriminated data types");

            // Verify the field s_dataDeserializationInstance does NOT exist
            var dataField = serializationProvider.Fields
                .FirstOrDefault(f => f.Name == "s_dataDeserializationInstance");
            Assert.IsNull(dataField, "s_dataDeserializationInstance field should NOT exist for abstract/discriminated data types");

            // Verify the IJsonModel<T>.Create method body does NOT reference DataDeserializationInstance
            var createMethod = serializationProvider.Methods
                .FirstOrDefault(m => m.Signature.Name == "Create");
            Assert.IsNotNull(createMethod, "IJsonModel<T>.Create method should exist");
            var createBody = createMethod!.BodyStatements?.ToDisplayString();
            Assert.IsNotNull(createBody);
            Assert.That(createBody, Does.Not.Contain("DataDeserializationInstance"),
                "IJsonModel<T>.Create should not reference DataDeserializationInstance for abstract data types");

            // Verify the GetFormatFromOptions method body does NOT reference DataDeserializationInstance
            var getFormatMethod = serializationProvider.Methods
                .FirstOrDefault(m => m.Signature.Name == "GetFormatFromOptions");
            Assert.IsNotNull(getFormatMethod, "IPersistableModel<T>.GetFormatFromOptions method should exist");
            var getFormatBody = getFormatMethod!.BodyStatements?.ToDisplayString();
            Assert.IsNotNull(getFormatBody);
            Assert.That(getFormatBody, Does.Not.Contain("DataDeserializationInstance"),
                "GetFormatFromOptions should not reference DataDeserializationInstance for abstract data types");
            Assert.That(getFormatBody, Does.Contain("\"J\""),
                "GetFormatFromOptions should return \"J\" directly for abstract data types");
        }

        private static InputDecoratorInfo BuildArmProviderSchema(
            InputModelType resourceModel,
            IReadOnlyList<ResourceMethod> methods,
            string resourceIdPattern,
            string resourceType,
            string? singletonResourceName,
            ResourceScope resourceScope,
            string? resourceName)
        {
            var options = new System.Text.Json.JsonSerializerOptions
            {
                PropertyNamingPolicy = System.Text.Json.JsonNamingPolicy.CamelCase,
            };

            var resourceSchema = new Dictionary<string, object?>
            {
                ["resourceModelId"] = resourceModel.CrossLanguageDefinitionId,
                ["resourceIdPattern"] = resourceIdPattern,
                ["resourceType"] = resourceType,
                ["resourceScope"] = resourceScope.ToString(),
                ["methods"] = methods.Select(m => new Dictionary<string, string>
                {
                    ["methodId"] = m.InputMethod.CrossLanguageDefinitionId,
                    ["kind"] = m.Kind.ToString(),
                    ["operationPath"] = m.OperationPath,
                    ["operationScope"] = m.OperationScope.ToString()
                }).ToArray<object>(),
                ["singletonResourceName"] = singletonResourceName,
                ["resourceName"] = resourceName,
            };

            var arguments = new Dictionary<string, BinaryData>
            {
                ["resources"] = BinaryData.FromObjectAsJson(new[] { resourceSchema }, options),
                ["nonResourceMethods"] = BinaryData.FromObjectAsJson(Array.Empty<object>(), options)
            };

            return new InputDecoratorInfo("Azure.ClientGenerator.Core.@armProviderSchema", arguments);
        }
    }
